 1	import React, { FC } from 'react';
 2	
 3	import { ConfigMapModel, modelToGroupVersionKind } from '@kubevirt-ui/kubevirt-api/console';
 4	import SysprepInfo from '@kubevirt-utils/components/SysprepModal/SysprepInfo';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { isEmpty } from '@kubevirt-utils/utils/utils';
 7	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 8	import { Alert, AlertVariant, DescriptionList, Stack, StackItem } from '@patternfly/react-core';
 9	
10	import Loading from '../Loading/Loading';
11	import VirtualMachineDescriptionItem from '../VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
12	
13	export const SysprepDescription: FC<{
14	  error?: Error;
15	  loaded?: boolean;
16	  selectedSysprepName?: string;
17	}> = ({ error, loaded, selectedSysprepName }) => {
18	  const { t } = useKubevirtTranslation();
19	
20	  if (error) {
21	    return (
22	      <Alert isInline title={t('Error')} variant={AlertVariant.danger}>
23	        {error?.message}
24	      </Alert>
25	    );
26	  }
27	
28	  if (!loaded) {
29	    return <Loading />;
30	  }
31	
32	  return (
33	    <Stack hasGutter>
34	      <StackItem>
35	        <SysprepInfo />
36	      </StackItem>
37	      <StackItem>
38	        <DescriptionList
39	          className="pf-v6-c-description-list"
40	          columnModifier={{ lg: '1Col', xl: '2Col' }}
41	          isCompact
42	        >
43	          <VirtualMachineDescriptionItem
44	            descriptionData={
45	              isEmpty(selectedSysprepName) ? (
46	                t('Not available')
47	              ) : (
48	                <ResourceLink
49	                  groupVersionKind={modelToGroupVersionKind(ConfigMapModel)}
50	                  linkTo={false}
51	                  name={selectedSysprepName}
52	                />
53	              )
54	            }
55	          />
56	        </DescriptionList>
57	      </StackItem>
58	    </Stack>
59	  );
60	};

